var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"저기군요.","JPN":"あそこですね。","ENG":"There it is.","TWN":"就在那裡呢。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"저게 당신이 말한 그 방주야? 상당히 낡았는데?","JPN":"あれがあなたの言っていた箱舟？　結構ボロいのね？","ENG":"So that's the Ark you were talking about? But it looks ancient!","TWN":"那就是你說的方舟？看起來很破舊啊？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님. 식별코드 확인됐습니다.","JPN":"副戦隊長殿。識別コードの確認ができました。","ENG":"Deputy Commander. We've confirmed the identification code.","TWN":"副隊長，已確認識別代碼。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"순양함 코핀–6. 퇴역 전투함을 개조해서 만든 수송선입니다.","JPN":"巡洋艦コフィン-6。退役戦闘艦を改造した輸送船です。","ENG":"Cruiser Coffin-6. It's a retired warship modified into a cargo ship.","TWN":"是由退役戰艦《巡洋艦科芬-6》改造的運輸船。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이주는 고사하고 전투에도 쓰기 힘들어 보이는군.","JPN":"移住どころか戦闘に使うことすら厳しそうに見えるな。","ENG":"It looks hardly capable of combat, let alone transporting us to an entirely new world.","TWN":"別說遷移了，這東西看起來連要戰鬥都沒辦法。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_BUTTON_SELECT"},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"나유빈, 정말 제대로 찾아온 건가?","JPN":"イチノセ、本当にここで合っているのか？","ENG":"Are you sure this is the right ship, Yubin?","TWN":"羅瑜斌，你真的沒來錯地方嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"겉모습은 중요하지 않아요. 분명 시공간 종료를 견딜 수 있는 장비가 있을 겁니다.","JPN":"肝心なのは見た目じゃありません。きっと時空間終了に\\n耐えられる装備があるはずです。","ENG":"Looks can be deceiving. I'm certain it has some kind of equipment that will shelter us from the spacetime abortion.","TWN":"外觀並不重要，它一定安裝了能夠承受時空終止的設備。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"생존자들을 옮겨 태우려면 시간이 필요합니다. 그동안 함선의 시스템을 확인해 주세요.","JPN":"生存者たちの移乗には時間がかかります。\\nその間、艦船のシステムを確認してください。","ENG":"We need more time to board all the survivors. Please check the ship's systems in the meantime.","TWN":"把倖存者轉移到船上需要點時間。在這之前，請先確認艦船的系統。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"중상자만 들것으로 옮겨! 걸을 수 있는 사람은 어서 탑승해!","JPN":"担架は重症者にのみ使え！　歩ける者はとっとと乗り込め！","ENG":"Carry only the gravely wounded on the stretchers! Everyone else, walk onboard!","TWN":"重傷患用擔架移動！能自己走的快點上船！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"남은 물자도 전부 실어야 한다! 굶어 죽기 싫으면 얼른 움직여!","JPN":"残りの物資も全部運び込むんだ！\\n飢え死にしたくなければテキパキ動け！","ENG":"We have to load up all the remaining supplies too! Get moving if you don't want to starve to death!","TWN":"剩餘物資也要全部搬上船！不想餓死就快點行動！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"함교, 재기동은 순조롭나?","JPN":"艦橋、再起動は順調に進んでいるか？","ENG":"Bridge, how's the reactivation coming along?","TWN":"艦橋，重啟得順利嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"항법 장치가 너무 구식이라 애를 먹고 있습니다.","JPN":"航法装置があまりにも旧式なため、苦労しています。","ENG":"Not so smoothly. The navigation system is so outdated.","TWN":"導航裝置的型式太老舊了，非常棘手。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_UI_BUTTON_SELECT"},{"id":"L24_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"동력기관도 마찬가지라, 지금으로선 구조를 파악하는 것부터가 어려운 상황입니다.","JPN":"動力機関も同様でして、現状では\\n構造を把握することすら困難な状況です。","ENG":"Same with the engine. We're having enough trouble trying to figure out the architecture.","TWN":"動力機關也是。依目前的狀況，要掌握結構也很困難。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"낭패로군......","JPN":"まずいな……","ENG":"This can't be good...","TWN":"這可麻煩了……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알겠다. 특이 사항이 있으면 즉각 보고하도록.","JPN":"わかった。異変があった場合は即刻報告するように。","ENG":"Very well. Report anything special to me right away.","TWN":"我知道了，如果發現特殊情況，立即向我報告。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"예상보다 시간이 더 걸리겠어. 괜찮겠나.","JPN":"すまないが、予想よりも時間がかかりそうだ。","ENG":"This will take longer than we thought. Is that going to be okay?","TWN":"時間花得比預想的還要多，沒問題吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"방금 들린 소리......","JPN":"今の音は……","ENG":"What was that sound?","TWN":"……剛剛聽到的聲音是？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"나유빈, 너도 들었나?","JPN":"イチノセ、聞こえたか？","ENG":"Did you hear that too, Yubin?","TWN":"羅瑜斌，你也聽到了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"......예. 아무래도 조금 늦은 것 같군요.","JPN":"……はい。どうやら間に合わなかったようです。","ENG":"Yes. I'm afraid we're running a bit behind schedule.","TWN":"……是的，看來還是太晚了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"최대한 탈출 준비를 서둘러 주세요. 저도 오래 막을 수는 없을 겁니다.","JPN":"大至急、脱出の準備をしてください。\\n僕でも長くは食い止められないでしょうから。","ENG":"Please expedite the preparations as much as possible. I won't be able to hold them off for too long.","TWN":"請儘快準備逃離，我撐不了太久。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"막다니? 뭘 막겠다는 거야?","JPN":"食い止める？　何を食い止めるというの？","ENG":"Hold them off? Hold what off?","TWN":"撐？撐是什麼意思？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"큰일입니다, 부전대장님!","JPN":"大変です、副戦隊長殿！","ENG":"It's an emergency, Deputy Commander!","TWN":"不好了，副隊長！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L43_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"전방에 제 6종 침식체 출현! 지원이 필요합니다!","JPN":"前方に第6種侵食体出現！　至急支援を！","ENG":"Category 6 sighted ahead! We need back up!","TWN":"前方出現6類侵蝕體！我們需要支援！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"6종이라고? 방금 전까지 아무 징후도 없었잖아?","JPN":"第6種ですって？　さっきまで何の前触れもなかったでしょう？","ENG":"Category 6? But there weren't any indications till just now!","TWN":"6類？剛才為止不是什麼徵兆也沒有嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"하지만 오는 길에 맞닥뜨렸던 놈과 같은 종류입니다!","JPN":"しかし、道中で遭遇した奴と同じ種類です！","ENG":"It's the same type of C.O. we met on the way here!","TWN":"但那和剛才在路上遇到的傢伙是同一種類！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"그런데, 날개가......!","JPN":"ただ、翼が……！","ENG":"But... its wings are...","TWN":"可是，翅膀……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"아하하하하! 날개를 뜯어 버리니 벌레처럼 기는 꼴이 볼 만하구나!","JPN":"アハハハハ！　翼をもぎ取れば虫のように\\n這いずりおって、実に見ものじゃのう！","ENG":"Ah hah hah hah hah! Look at it crawl like a worm without its wings! Oh, what a sight!","TWN":"啊哈哈哈哈！把翅膀撕掉後，簡直就像隻螻蟻一樣！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L2_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"그렇지 않느냐, 시종?","JPN":"そうは思わぬか？　妾の僕よ。","ENG":"Isn't that right, my servant?","TWN":"對吧，侍從？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"본신을 드러내지 않고도 세피라의 수호자를 이리 간단히 멸하시다니, 과연 주인님이십니다.","JPN":"御身を地上に降ろすまでもなく、セフィラの守護者を\\nこうも容易く滅ぼされるとは、さすがはご主人様です。","ENG":"Only you could dispatch the Guardian of Sephira so deftly even without revealing yourself, my Mistress.","TWN":"沒有現出真身就如此輕易地滅掉了塞菲拉守護者，真不愧是主人。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_SKILL_START"},{"id":"L6_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"후훗. 칭송은 아껴 두어라. 그리 대단한 일도 아니거늘.","JPN":"フフッ。そう讃えずともよい。これしきは造作もないことじゃ。","ENG":"Heh heh. Spare your praise. That was hardly impressive.","TWN":"呵呵，讚美就省了吧，這沒什麼了不起的。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"신성의 찌꺼기만 남았을 뿐, <color=#ffd34c>그년</color>에게 본질을 빼앗기고 껍데기만 남은 것들이다.","JPN":"こやつらの中身は神性存在の残りかすじゃ。\\n<color=#ffd34c>あの女</color>に本質をごっそり抜かれておる。","ENG":"They may be left with scraps of Divinity, but in truth they are no more than empty husks with their essence robbed by <color=#ffd34c>that strumpet</color>.","TWN":"只不過是神聖的殘渣，被<color=#ffd34c>她</color>奪取本質後，就只剩下空殼而已。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"가지고 노는 재미로는 5종보다 떨어지지. 그것들은 발악이란 걸 할 줄 알거든.","JPN":"弄り甲斐で言えば、第5種の方が幾分マシじゃ。\\nあやつらは悪足掻きしよるからのう。","ENG":"Really, these creatures make much less entertaining playthings than Category 5 ones. At least they know how to resist.","TWN":"樂趣輸給了5類，至少它們還懂得掙扎。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"주인님! 난 아직 주먹 한 번 못 휘둘러 봤다고!","JPN":"なぁ、主様！　アタシはまだいっぺんも拳を振るってねえんだ！","ENG":"Mistress! I never even got the chance to swing my fists!","TWN":"主人！也讓我揮個一拳嘛！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"마무리는 나한테 맡겨!","JPN":"トドメはアタシに任せなって！","ENG":"Let me finish it off!","TWN":"收尾就交給我吧！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"진정하렴, 동생아. 종복된 자로서 주인님의 여흥을 깨뜨리는 것은 금물이란다.","JPN":"控えなさい、我が妹よ。従僕たる者として、\\nご主人様の興を削ぐなど言語道断だ。","ENG":"Easy now, sister. As mere servants, we are not to disturb our Mistress's pursuit of leisure.","TWN":"冷靜點，妹妹。身為僕從怎麼可以壞了主人的興致呢。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"됐다, 시종. 안 그래도 슬슬 질려 가던 참이었어.","JPN":"よいのじゃ、僕よ。そろそろ飽きてきたところじゃからのう。","ENG":"It's fine, my servant. I was growing rather tired of this anyway.","TWN":"好啦，侍從。我差不多也玩膩了。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"다음은 유마, 네게 맡기마.","JPN":"後はユマ、其方に任せるぞ。","ENG":"I'll leave the rest to you, Yuma.","TWN":"剩下的就交給你吧，游馬。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"가서 저 벌레의 최후를 멋지게 장식해 주도록.","JPN":"あの虫の最期を華々しく飾ってやるがよい。","ENG":"You may go grant that worm a most glorious death.","TWN":"去了結掉那隻蟲子吧。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"크하하핫! 좋았어!","JPN":"ガハハハッ！　よし来た！","ENG":"Bwa hah hah! Awesome!","TWN":"哇哈哈哈！太好了！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"그런데......","JPN":"ところで……","ENG":"By the way...","TWN":"話說回來……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"시종, 저기 옹기종기 모여 있는 것들이 보이느냐?","JPN":"僕よ、あそこに寄り集まっている奴らが見えるか？","ENG":"Servant, do you see those things gathered about over there?","TWN":"侍從，你有看到聚集在那邊的那群人嗎？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"호오...... 저 자들은......","JPN":"ほう……あの者たちは……","ENG":"Oh... They are...","TWN":"哦……那群人啊……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이거, 오늘은 아무래도 주인님을 위한 축제가 열린 것 같군요.","JPN":"これはこれは……どうやら今日はご主人様のための\\n祝宴が催される日のようです。","ENG":"It seems that today will become a festival in your honor, Mistress.","TWN":"看來今天是專為主人舉辦的慶典呢。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};